svg.script:

document.addEventListener('DOMContentLoaded', () => {
  const text = document.getElementById('title-text');
  const container = document.getElementById('title-container');
  let currentSize = 110; 

  // Loop shrinks the font size 1px at a time until the text physically fits inside the 230px height limit
  while(text.scrollHeight > container.clientHeight && currentSize > 20) {
    currentSize--;
    text.style.fontSize = currentSize + 'px';
  }
});
